import React, { useState, useEffect } from 'react';
import axios from 'axios';
import TopNav from './TopNav';
import './Insights.css';

const Insights = () => {
  const [insights, setInsights] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchInsights();
  }, []);

  const fetchInsights = async () => {
    try {
      const res = await axios.get('/meetings?limit=20');
      const meetings = res.data.meetings || [];
      const withInsights = meetings.filter(m => m.summary && m.transcriptionStatus === 'Completed');
      setInsights(withInsights);
    } catch (error) {
      console.error('Error fetching insights:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="insights-screen">
        <TopNav />
        <div className="insights-wrapper">
          <div className="insights-content">
            <div className="loading">Loading...</div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="insights-screen">
      <TopNav />
      <div className="insights-wrapper">
        <div className="insights-top-bar">
          <h1 className="insights-title">Insights</h1>
        </div>

        <div className="insights-content">
          {insights.length === 0 ? (
            <div className="empty-state">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" style={{ color: '#A1A1A6', marginBottom: '16px' }}>
                <line x1="18" y1="20" x2="18" y2="10"></line>
                <line x1="12" y1="20" x2="12" y2="4"></line>
                <line x1="6" y1="20" x2="6" y2="14"></line>
              </svg>
              <p>No insights available</p>
            </div>
          ) : (
            <div className="insights-grid">
              {insights.map(meeting => (
                <div key={meeting._id} className="insight-card">
                  <div className="insight-header">
                    <div className="insight-title">{meeting.title || 'Untitled Meeting'}</div>
                    <div className="insight-date">
                      {new Date(meeting.createdAt).toLocaleDateString()}
                    </div>
                  </div>
                  {meeting.summary?.keyPoints && meeting.summary.keyPoints.length > 0 && (
                    <div className="insight-section">
                      <h3>Key Points</h3>
                      <ul>
                        {meeting.summary.keyPoints.slice(0, 3).map((point, idx) => (
                          <li key={idx}>{point}</li>
                        ))}
                      </ul>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Insights;
